SELECT count(*) FROM char_name, cast_info, name, role_type, title, aka_name, movie_keyword, movie_companies WHERE cast_info.person_role_id = char_name.id AND cast_info.person_id = name.id AND cast_info.role_id = role_type.id AND cast_info.movie_id = title.id AND aka_name.person_id = name.id AND movie_keyword.movie_id = title.id AND movie_companies.movie_id = title.id;